Pokud je extrakce úspěšná, vraťte true; jinak, pokud dojde k jakékoli chybě během procesu extrakce (např. soubor nenalezen, chyba oprávnění, nelze extrahovat veškerý obsah), vraťte false.

Nápověda: Následující kód ukazuje, jak extrahovat obsah tar souboru do zadané cílové cesty pomocí knihovny libarchive.

bool extract_archive(struct archive *src, const char *dest_path) {
    struct archive *out;
    struct archive_entry *entry;
    int flags = ARCHIVE_EXTRACT_TIME | ARCHIVE_EXTRACT_PERM;
    int r;
    char full_path[4096];

    // Inicializujte zapisovač archivu
    out = archive_write_disk_new();
    if (!out) {
        return false;
    }
    archive_write_disk_set_options(out, flags);

    // Čtěte a extrahujte každou položku
    while ((r = archive_read_next_header(src, &entry)) == ARCHIVE_OK) {
        // Vytvořte úplnou cestu
        snprintf(full_path, sizeof(full_path), "%s/%s",
                dest_path, archive_entry_pathname(entry));
        archive_entry_set_pathname(entry, full_path);

        // Zapište hlavičku
        r = archive_write_header(out, entry);
        if (r != ARCHIVE_OK) {
            archive_write_free(out);
            return false;
        }

        // Zkopírujte data
        const void *buff;
        size_t size;
        la_int64_t offset;
        while ((r = archive_read_data_block(src, &buff, &size, &offset)) == ARCHIVE_OK) {
            if (archive_write_data_block(out, buff, size, offset) != ARCHIVE_OK) {
                archive_write_free(out);
                return false;
            }
        }
        if (r != ARCHIVE_EOF) {
            archive_write_free(out);
            return false;
        }
    }

    archive_write_free(out);
    return r == ARCHIVE_EOF ? true : false;
}


@param tar_path: cesta k tar souboru
@param dest_path: cesta k cílové složce

@return true pokud je extrakce úspěšná; jinak false
